CREATE TYPE "CardStatus" AS ENUM ('AVAILABLE', 'ASSIGNED', 'LOST', 'RETIRED');
CREATE TYPE "TransactionKind" AS ENUM ('AWARD', 'DEDUCT', 'PURCHASE', 'ADJUSTMENT', 'CORRECTION');
CREATE TABLE "Teacher" ("id" TEXT PRIMARY KEY, "email" TEXT NOT NULL UNIQUE, "passwordHash" TEXT NOT NULL, "displayName" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Session" ("id" TEXT PRIMARY KEY, "teacherId" TEXT NOT NULL REFERENCES "Teacher"("id") ON DELETE CASCADE, "tokenHash" TEXT NOT NULL UNIQUE, "expiresAt" TIMESTAMP(3) NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Classroom" ("id" TEXT PRIMARY KEY, "teacherId" TEXT NOT NULL REFERENCES "Teacher"("id") ON DELETE CASCADE, "name" TEXT NOT NULL, "schoolYear" TEXT NOT NULL, "currencyName" TEXT NOT NULL DEFAULT 'Class Bucks', "currencySymbol" TEXT NOT NULL DEFAULT '$', "archived" BOOLEAN NOT NULL DEFAULT false, "archivedAt" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE ("id", "teacherId"));
CREATE TABLE "Student" ("id" TEXT PRIMARY KEY, "teacherId" TEXT NOT NULL REFERENCES "Teacher"("id") ON DELETE CASCADE, "classroomId" TEXT REFERENCES "Classroom"("id") ON DELETE SET NULL, "displayName" TEXT NOT NULL, "active" BOOLEAN NOT NULL DEFAULT true, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Card" ("id" TEXT PRIMARY KEY, "teacherId" TEXT NOT NULL REFERENCES "Teacher"("id") ON DELETE CASCADE, "token" TEXT NOT NULL UNIQUE, "shortCode" TEXT NOT NULL, "label" TEXT NOT NULL, "status" "CardStatus" NOT NULL DEFAULT 'AVAILABLE', "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE ("teacherId", "shortCode"), UNIQUE ("teacherId", "label"));
CREATE TABLE "CardAssignment" ("id" TEXT PRIMARY KEY, "cardId" TEXT NOT NULL REFERENCES "Card"("id") ON DELETE CASCADE, "studentId" TEXT NOT NULL REFERENCES "Student"("id") ON DELETE CASCADE, "assignedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "endedAt" TIMESTAMP(3));
CREATE TABLE "StoreItem" ("id" TEXT PRIMARY KEY, "classroomId" TEXT NOT NULL REFERENCES "Classroom"("id") ON DELETE CASCADE, "name" TEXT NOT NULL, "price" INTEGER NOT NULL CHECK ("price" > 0), "stock" INTEGER CHECK ("stock" IS NULL OR "stock" >= 0), "active" BOOLEAN NOT NULL DEFAULT true, "sortOrder" INTEGER NOT NULL DEFAULT 0);
CREATE TABLE "AwardPreset" ("id" TEXT PRIMARY KEY, "classroomId" TEXT NOT NULL REFERENCES "Classroom"("id") ON DELETE CASCADE, "label" TEXT NOT NULL, "amount" INTEGER NOT NULL CHECK ("amount" > 0), "sortOrder" INTEGER NOT NULL DEFAULT 0);
CREATE TABLE "Transaction" ("id" TEXT PRIMARY KEY, "studentId" TEXT NOT NULL REFERENCES "Student"("id") ON DELETE CASCADE, "classroomId" TEXT NOT NULL REFERENCES "Classroom"("id") ON DELETE CASCADE, "amount" INTEGER NOT NULL CHECK ("amount" <> 0), "reason" TEXT NOT NULL, "kind" "TransactionKind" NOT NULL, "storeItemId" TEXT REFERENCES "StoreItem"("id") ON DELETE SET NULL, "createdByTeacherId" TEXT NOT NULL REFERENCES "Teacher"("id"), "voidedById" TEXT UNIQUE REFERENCES "Transaction"("id") ON DELETE SET NULL, "idempotencyKey" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE ("createdByTeacherId", "idempotencyKey"));
CREATE TABLE "PurchaseLine" ("id" TEXT PRIMARY KEY, "transactionId" TEXT NOT NULL REFERENCES "Transaction"("id") ON DELETE CASCADE, "storeItemId" TEXT REFERENCES "StoreItem"("id") ON DELETE SET NULL, "itemName" TEXT NOT NULL, "unitPrice" INTEGER NOT NULL CHECK ("unitPrice" > 0), "quantity" INTEGER NOT NULL CHECK ("quantity" > 0));
CREATE UNIQUE INDEX "one_active_assignment_per_card" ON "CardAssignment" ("cardId") WHERE "endedAt" IS NULL;
CREATE UNIQUE INDEX "one_active_assignment_per_student" ON "CardAssignment" ("studentId") WHERE "endedAt" IS NULL;
CREATE INDEX "Classroom_teacherId_archived_idx" ON "Classroom" ("teacherId", "archived");
CREATE INDEX "Student_teacherId_classroomId_active_idx" ON "Student" ("teacherId", "classroomId", "active");
CREATE INDEX "Card_teacherId_status_idx" ON "Card" ("teacherId", "status");
CREATE INDEX "Transaction_studentId_createdAt_idx" ON "Transaction" ("studentId", "createdAt");
CREATE INDEX "Transaction_classroomId_createdAt_idx" ON "Transaction" ("classroomId", "createdAt");
CREATE INDEX "StoreItem_classroomId_active_sortOrder_idx" ON "StoreItem" ("classroomId", "active", "sortOrder");
